var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아까보다 안색이 더 안 좋으세요.","JPN":"さっきより顔色がもっと悪くなっています。","ENG":"You look worse than before.","TWN":"你的臉色好像變得更差咧。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"전보다 더 심한 환청이 들려. 마치 진짜 내 옆에 사람들이 있는 것처럼.","JPN":"前より幻聴が激しくなった。まるで、すぐ目の前にいるように。　","ENG":"The auditory hallucinations are getting worse. I hear them as if there really is someone right next to me.","TWN":"我的幻聽似乎變得更嚴重了，感覺就在我耳邊說話一樣。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤, 정말 이 목소리가 들리지 않나?","JPN":"アーシャ、本当に君には聞こえないのか？","ENG":"Asha. Do you really not hear this voice?","TWN":"阿莎，你真的什麼都沒聽到嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"제 눈엔 아디트야 님이 더 무서워요.","JPN":"アーディティヤ様、怖いです。","ENG":"You're starting to scare me, Miss Aditya.","TWN":"我覺得你比較可怕。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아직 내 워치는 멀쩡하다. 이 정도도 못 버틸 만큼 나약하진 않아.","JPN":"ウォッチなら問題ない。この程度も耐えられないほど私は弱くない。","ENG":"My Watch is still intact. I am not weak enough to not be able to endure this much.","TWN":"我的能量環還沒壞，應該沒有弱到不堪一擊。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그래서 더 무섭다는 거예요…….","JPN":"だから余計に怖いんです……","ENG":"That's why you're scaring me...","TWN":"就是這樣才覺得更可怕……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"누가 여기서 계속 아디트야 님을 불렀다고 했죠? 누군지 기억이 나시나요?","JPN":"誰かが、ここでアーディティヤ様をずっと呼んでいたんですよね？　それが誰だか思い出せますか？","ENG":"You said that someone kept calling you from here. Do you remember who it is?","TWN":"你說有人一直在喊你的名字對吧？那你記得是誰嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……누군지는 모르겠군.","JPN":"……いや、わからない。","ENG":"...I can't say that I do.","TWN":"……我不知道是誰。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그저 나를 기다리고 있었다고 말했다.","JPN":"私を待っていたと言っていた。","ENG":"All he said was that he was waiting for me.","TWN":"他只說他一直在等我。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이곳이 정말 천년의 역사를 자랑했던 도시인 걸까요?","JPN":"本当にここが、あの千年の歴史を持つ都市なんでしょうか？","ENG":"Is this really the city with a thousand years of history?","TWN":"這裡真的是以千年歷史為傲的城市嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"글쎄. 그건 나도 잘 모르겠군.","JPN":"さあ、それは私にもよくわからない。","ENG":"Well, I'm not sure about that.","TWN":"不知道，我也不清楚。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만 확실한 건…….","JPN":"だがこれだけは確かだ……","ENG":"But I can say this one thing…","TWN":"但能夠確定的是……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이 도시로 안내한 목소리들이 나에게 아주 많은 관심이 있다는 거야.","JPN":"この都市に私を導いた声の主たちは、私をかなり注目しているらしい。","ENG":"The voices that have guided me to this city are very interested in me.","TWN":"將我帶到這座城市的聲音，對我非常有興趣。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님에게 관심을 갖고 있다면 제대로 찾아온 걸지도 몰라요.","JPN":"それが本当なら、ここに来たのは正解だったのかもしれません。","ENG":"Then we might have come to the right place if they are taking an interest in you.","TWN":"對你很有興趣的話，就表示我們找對地方了吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그것들이 나침반과도 연관되어 있다면 말이지.","JPN":"それらが羅針盤とも関係していればな。","ENG":"If they are correlated with the compass too, that is.","TWN":"若這些都與指南針有相關的話。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만 진전이 없을 시 바로 빠져나간다.","JPN":"だが、なんの収穫も見込めないと判断したら、すぐにここを離れる。","ENG":"But we leave right away if there is no progress.","TWN":"只要沒有進展就要立刻閃人。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"어떤 위험 요소가 있는지도 모르는 곳에서 느긋하게 수색만 할 수는 없어.","JPN":"どんな危険が潜んでいるかもわからない場所で、いつまでも探索を続けるわけにはいかない。","ENG":"We can't take our time searching this place when we don't even know what dangers might lurk here.","TWN":"我們對這個地方也不熟悉，不知道會有甚麼危險，此地不宜久留。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"혹여나 네가 말한 그 <color=#ffd34c>전설 속 침식체</color>가 나타난다면 더더욱.","JPN":"君が話した<color=#ffd34c>伝説の侵食体</color>が本当にいるとすればなおさらだ。","ENG":"Even more so if that <color=#ffd34c>legendary C.O.</color> you mentioned appears.","TWN":"萬一你說的那個<color=#ffd34c>傳說中的侵蝕體</color>出現的話，更是如此。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네? 하지만…….","JPN":"えっ？　でも……","ENG":"What? But...","TWN":"可是……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"개인의 소망이 그 주인을 잡아먹어서는 안 돼.","JPN":"叶えたい願いに、支配されてはいけない。","ENG":"You can't let your wish consume you.","TWN":"你的私慾不該於凌駕於你之上。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그건 망집으로 움직이는 침식체와 다를 바 없어.","JPN":"それでは、欲のままにただ動くだけの侵食体と同じだ。","ENG":"Then, you'll be no different from the C.O.s and their obsessions.","TWN":"否則你與那些被妄念驅使的侵蝕體有何異？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으으음…… 알겠어요.","JPN":"うう……わかりました。","ENG":"Erm... Okay.","TWN":"呃呃……好啦。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"개인의 소망은 목숨보다 중요하지 않다. 맞죠?","JPN":"願いを叶えることより、命を優先しろってことですよね？","ENG":"So, you're saying that my life is more important than my wishes, right?","TWN":"個人的私慾哪有命來得重要，對吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"정확해. 이해가 빨라서 좋군.","JPN":"そういうことだ。理解が早くて助かるよ。","ENG":"Correct. I'm glad you got that quickly.","TWN":"沒錯，你的理解力很好。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};